mapper.select:
SELECT o.id, o.order_no AS orderNo, o.order_status AS orderStatus, o.total_amount AS totalAmount, o.pay_amount AS payAmount, o.paid, o.after_sale_flag AS afterSaleFlag, o.create_time AS createTime, o.pay_time AS payTime FROM mall_order o WHERE o.user_id = #{userId}
AND o.order_status = #{request.orderStatus}
AND o.order_no LIKE CONCAT('%', #{request.orderNo}, '%')
AND EXISTS ( SELECT 1 FROM mall_order_item oi WHERE oi.order_id = o.id AND oi.product_name LIKE CONCAT('%', #{request.productName}, '%') )
ORDER BY o.create_time DESC
